## Scan Phase

### Main Scan Function:

```cpp
void VgiTableFunctionScan(
    ClientContext &context,
    TableFunctionInput &input,
    DataChunk &output) {

    auto &bind_data = input.bind_data->Cast<VgiTableFunctionBindData>();
    auto &global_state = input.global_state->Cast<VgiTableFunctionGlobalState>();

    std::lock_guard<std::mutex> lock(global_state.stream_lock);

    if (global_state.exhausted) {
        output.SetCardinality(0);
        return;
    }

    idx_t rows_read = 0;
    idx_t max_rows = STANDARD_VECTOR_SIZE;

    while (rows_read < max_rows) {
        // Get current batch or fetch next
        if (!global_state.current_batch || 
            global_state.current_batch_offset >= global_state.current_batch->num_rows()) {

            global_state.current_batch = global_state.stream->ReadNext();
            global_state.current_batch_offset = 0;

            if (!global_state.current_batch) {
                global_state.exhausted = true;
                break;
            }
        }

        // Calculate how many rows to read from current batch
        idx_t batch_remaining = global_state.current_batch->num_rows() - 
                                global_state.current_batch_offset;
        idx_t rows_to_read = MinValue(batch_remaining, max_rows - rows_read);

        // Convert Arrow arrays to DuckDB vectors
        ConvertArrowToDuckDB(
            global_state.current_batch,
            global_state.current_batch_offset,
            rows_to_read,
            bind_data.return_types,
            output,
            rows_read
        );

        global_state.current_batch_offset += rows_to_read;
        rows_read += rows_to_read;
    }

    output.SetCardinality(rows_read);
}
```

### Arrow to DuckDB Conversion:

```cpp
void ConvertArrowToDuckDB(
    const std::shared_ptr<arrow::RecordBatch> &batch,
    idx_t batch_offset,
    idx_t count,
    const vector<LogicalType> &types,
    DataChunk &output,
    idx_t output_offset) {

    for (idx_t col_idx = 0; col_idx < batch->num_columns(); col_idx++) {
        auto &arrow_array = batch->column(col_idx);
        auto &target = output.data[col_idx];

        ConvertArrowArray(
            arrow_array, 
            batch_offset, 
            count, 
            target, 
            output_offset,
            types[col_idx]
        );
    }
}

void ConvertArrowArray(
    const std::shared_ptr<arrow::Array> &array,
    idx_t offset,
    idx_t count,
    Vector &target,
    idx_t target_offset,
    const LogicalType &type) {

    // Handle nulls
    if (array->null_count() > 0) {
        auto &validity = FlatVector::Validity(target);
        for (idx_t i = 0; i < count; i++) {
            if (array->IsNull(offset + i)) {
                validity.SetInvalid(target_offset + i);
            }
        }
    }

    switch (type.id()) {
        case LogicalTypeId::BOOLEAN:
            ConvertBooleanArray(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::TINYINT:
            ConvertNumericArray<int8_t>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::SMALLINT:
            ConvertNumericArray<int16_t>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::INTEGER:
            ConvertNumericArray<int32_t>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::BIGINT:
            ConvertNumericArray<int64_t>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::FLOAT:
            ConvertNumericArray<float>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::DOUBLE:
            ConvertNumericArray<double>(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::VARCHAR:
            ConvertStringArray(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::BLOB:
            ConvertBinaryArray(array, offset, count, target, target_offset);
            break;
        case LogicalTypeId::LIST:
            ConvertListArray(array, offset, count, target, target_offset, type);
            break;
        case LogicalTypeId::STRUCT:
            ConvertStructArray(array, offset, count, target, target_offset, type);
            break;
        // ... more types
        default:
            throw NotImplementedException(
                "Arrow to DuckDB conversion not implemented for type: %s",
                type.ToString());
    }
}
```

### Numeric Array Conversion Template:

```cpp
template<typename T>
void ConvertNumericArray(
    const std::shared_ptr<arrow::Array> &array,
    idx_t offset,
    idx_t count,
    Vector &target,
    idx_t target_offset) {

    auto typed_array = std::static_pointer_cast<arrow::NumericArray<
        typename arrow::CTypeTraits<T>::ArrowType>>(array);
    auto data = FlatVector::GetData<T>(target);

    for (idx_t i = 0; i < count; i++) {
        if (!array->IsNull(offset + i)) {
            data[target_offset + i] = typed_array->Value(offset + i);
        }
    }
}
```

### String Array Conversion:

```cpp
void ConvertStringArray(
    const std::shared_ptr<arrow::Array> &array,
    idx_t offset,
    idx_t count,
    Vector &target,
    idx_t target_offset) {

    auto string_array = std::static_pointer_cast<arrow::StringArray>(array);
    auto data = FlatVector::GetData<string_t>(target);

    for (idx_t i = 0; i < count; i++) {
        if (!array->IsNull(offset + i)) {
            auto value = string_array->GetView(offset + i);
            data[target_offset + i] = StringVector::AddString(
                target, value.data(), value.size());
        }
    }
}
```

